import re
from collections import defaultdict

class WebAttackScanner:
    def __init__(self):
        self.sigs = {
            'SQL Injection': re.compile(r"(union\s+select|'\s*or\s*'|drop\s+table|;\s*--)", re.I),
            'XSS': re.compile(r'(<script|javascript:|onerror\s*=|onload\s*=)', re.I),
            'Path Traversal': re.compile(r'(\.\./|%2e%2e|/etc/passwd)', re.I),
            'Command Injection': re.compile(r'(;\s*cat\s|\|\s*whoami|`[^`]+`)', re.I),
        }
        self.results = defaultdict(list)

    def scan(self, requests):
        for req in requests:
            found = []
            for name, pat in self.sigs.items():
                if pat.search(req):
                    found.append(name)
                    self.results[name].append(req)
            icon = '🚨 ' + ' + '.join(found) if found else '✅ Clean'
            print(f'{icon}: {req[:60]}')

    def summary(self):
        print('\n=== SUMMARY ===')
        for attack, entries in sorted(self.results.items()):
            print(f'  {attack}: {len(entries)} detections')

