from datetime import datetime

class Timeline:
    FORMATS = {
        'apache': '%d/%b/%Y:%H:%M:%S %z',
        'syslog': '%b %d %H:%M:%S',
        'iso': '%Y-%m-%dT%H:%M:%S',
        'standard': '%Y-%m-%d %H:%M:%S',
    }
    def __init__(self): self.events = []

    def parse_ts(self, s, fmt):
        dt = datetime.strptime(s, self.FORMATS[fmt])
        if fmt == 'syslog': dt = dt.replace(year=2025)
        return dt.replace(tzinfo=None) if dt.tzinfo else dt

    def add(self, ts, source, desc, severity='INFO'):
        self.events.append({'time':ts,'source':source,'desc':desc,'sev':severity})

    def show(self):
        self.events.sort(key=lambda e: e['time'])
        icons = {'INFO':'🔵','WARNING':'🟡','HIGH':'🟠','CRITICAL':'🔴'}
        print('\n📅 SECURITY TIMELINE')
        for e in self.events:
            icon = icons.get(e['sev'],'⚪')
            print(f'  {e["time"]:%H:%M:%S} {icon} [{e["source"]:8s}] {e["desc"]}')

