import re
from collections import Counter

class Pipeline:
    def __init__(self):
        self.entries = []
        self.threats = []
        self.stats = {'lines':0,'parsed':0,'ips':Counter(),'status':Counter()}
        self.sigs = {'SQLi':re.compile(r"(union.*select|'\s*or)",re.I),
                     'XSS':re.compile(r'(<script|javascript:)',re.I),
                     'PathTraversal':re.compile(r'(\.\./|%2e%2e)',re.I)}

    def ingest(self, logs):
        print('📥 Stage 1: Ingesting...')
        pat = r'(\S+) .* \[(.*?)\] "(\S+) (\S+) \S+" (\d{3})'
        for line in logs:
            self.stats['lines'] += 1
            m = re.match(pat, line)
            if m:
                entry = {'ip':m.group(1),'path':m.group(4),'status':int(m.group(5)),'raw':line}
                self.entries.append(entry)
                self.stats['parsed'] += 1
                self.stats['ips'][entry['ip']] += 1
                self.stats['status'][str(entry['status'])] += 1
        print(f'   Parsed {self.stats["parsed"]}/{self.stats["lines"]}')

    def detect(self):
        print('🔍 Stage 2: Detecting...')
        for e in self.entries:
            for name, pat in self.sigs.items():
                if pat.search(e['path']):
                    self.threats.append({'type':name,'ip':e['ip'],'path':e['path']})
        print(f'   Found {len(self.threats)} threats')

    def report(self):
        print('📋 Stage 3: Report')
        print(f'\n  Lines: {self.stats["lines"]} | Parsed: {self.stats["parsed"]} | Threats: {len(self.threats)}')
        threat_types = Counter(t['type'] for t in self.threats)
        for t, c in threat_types.most_common():
            print(f'    {t}: {c}')
        risk = 'CRITICAL' if threat_types.get('SQLi',0) > 0 else 'HIGH' if self.threats else 'LOW'
        print(f'  Risk: {risk}')

