    for ts,_ in logs: d[ts[:5]]+=1
    for m in sorted(d):
        c=d[m]; print(f'{m} | {"█"*c} ({c}){" 🚨 SPIKE" if c>=4 else ""}')

def multi_attack(logs):
    import re
    sigs={'SQLi':re.compile(r"(union.*select|' or ')",re.I),'XSS':re.compile(r'<script',re.I),'PathTrav':re.compile(r'\.\.',re.I)}
    d=defaultdict(set)
    for ip,path in logs:
        for n,p in sigs.items():
            if p.search(path): d[ip].add(n)
    return {ip:sorted(v) for ip,v in d.items() if len(v)>=2}

def attack_summary(r):
    types=Counter(x['type'] for x in r); sevs=Counter(x['severity'] for x in r); ips=len(set(x['ip'] for x in r))
    lines=['=== ATTACK SUMMARY ===',f'Total attacks: {len(r)}',f'Unique attackers: {ips}','','By Type:']
    for t,c in types.most_common(): lines.append(f'  {t}: {c}')
    lines.append('\nBy Severity:')
    for s,c in sevs.most_common(): lines.append(f'  {s}: {c}')
    risk='CRITICAL' if sevs.get('CRITICAL',0)>0 else 'HIGH' if sevs.get('HIGH',0)>0 else 'MEDIUM'
    lines.append(f'\nRisk: {risk}')
    return '\n'.join(lines)

def baseline(d):
    import statistics
    return (statistics.mean(d),statistics.stdev(d))

def thresholds(d,sens=2):
    import statistics; m=statistics.mean(d); s=statistics.stdev(d)
    return (m-sens*s, m+sens*s)

def monitor(hist,new):
    import statistics; m=statistics.mean(hist); s=max(statistics.stdev(hist),1)
    hi=m+2*s; lo=m-2*s
    for i,v in enumerate(new,1):
        if v>hi: print(f'Hour {i}: {v:5.0f} 🚨 HIGH')
        elif v<lo: print(f'Hour {i}: {v:5.0f} 🚨 LOW')
        else: print(f'Hour {i}: {v:5.0f} ✅')

def anomaly_count(hist,new):
    import statistics; m=statistics.mean(hist); s=max(statistics.stdev(hist),1)
    hi,lo=m+2*s,m-2*s
    c=sum(1 for v in new if v>hi or v<lo)
    return (c, c/len(new)*100)

def error_spike(tots,errs,th=10):
    for i,(t,e) in enumerate(zip(tots,errs),1):
        pct=e/t*100 if t else 0
        print(f'Hour {i}: {pct:.1f}% {"🚨 SPIKE" if pct>th else "✅"}')

def histogram(times):
    c=Counter(t[:2] for t in times)
    for h in sorted(c): print(f'Hour {h}: {"█"*c[h]} ({c[h]})')

def percentile_check(hist,new):
    s=sorted(hist); p95=s[int(len(s)*0.95)]
    print(f'P95 threshold: {p95}')
    for i,v in enumerate(new,1):
        print(f'Hour {i}: {v:5.0f} {"🚨 ABOVE P95" if v>p95 else "✅"}')

def rolling_monitor(data,w=5):
    import statistics
    for i in range(w,len(data)):
        window=data[i-w:i]; avg=statistics.mean(window); s=max(statistics.stdev(window),1)
        v=data[i]; flag='🚨' if abs(v-avg)>2*s else '✅'
        print(f'Val {i+1}: {v:5.0f} {flag} (avg: {avg:.0f})')

